class Solution:
    def partitionDisjoint(self, nums):
        n = len(nums)
        max_left = [0] * n
        running = nums[0]
        for i in range(n):
            running = max(running, nums[i])
            max_left[i] = running
        min_right = [0] * n
        running = nums[-1]
        for i in range(n - 1, -1, -1):
            running = min(running, nums[i])
            min_right[i] = running
        for i in range(n - 1):
            if max_left[i] <= min_right[i + 1]:
                return i + 1
        return n - 1

