var partitionDisjoint = function(nums) {
    let leftMax = nums[0];
    let curMax = nums[0];
    let cut = 0;
    for (let i = 1; i < nums.length; i++) {
        curMax = Math.max(curMax, nums[i]);
        if (nums[i] < leftMax) {
            cut = i;
            leftMax = curMax;
        }
    }
    return cut + 1;
